using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using System;

namespace ContosoUniversity.Tests
{
    /// <summary>
    /// Shared helper for creating InMemory DbContext instances for testing.
    /// Each test method should use a unique database name to avoid cross-test interference.
    /// </summary>
    public static class TestHelper
    {
        public static SchoolContext CreateInMemoryContext(string databaseName = null)
        {
            databaseName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName)
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string databaseName = null)
        {
            var context = CreateInMemoryContext(databaseName);
            DbInitializer.Initialize(context);
            return context;
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_ValidInputs_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_ValidInputs_CalculatesTotalPages()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

            // Assert
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        }

        [TestMethod]
        public void Constructor_ValidInputs_ContainsAllItems()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act
            var list = new PaginatedList<int>(items, 10, 1, 3);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual(1, list[0]);
            Assert.AreEqual(2, list[1]);
            Assert.AreEqual(3, list[2]);
        }

        [TestMethod]
        [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
        [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 = 4 pages")]
        [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
        [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
        [DataRow(10, 10, 1, DisplayName = "10 items, page size 10 = 1 page")]
        [DataRow(11, 10, 2, DisplayName = "11 items, page size 10 = 2 pages")]
        public void Constructor_VariousCounts_CalculatesCorrectTotalPages(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            // Assert
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5); // 2 total pages, on page 2

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_FirstPageOfMany_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5); // 2 total pages, on page 1

            // Assert
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
            Assert.AreEqual(2, result.PageIndex);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 12).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 3, 5); // 12 items, page 3, page size 5

            // Assert
            Assert.AreEqual(2, result.Count); // only 2 items remaining
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_SingleItem_ReturnsCorrectly()
        {
            // Arrange
            var source = new[] { 42 }.AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(42, result[0]);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_WithStringType_WorksCorrectly()
        {
            // Arrange
            var source = new[] { "Alice", "Bob", "Charlie", "Diana", "Eve" }.AsQueryable();

            // Act
            var result = PaginatedList<string>.Create(source, 1, 2);

            // Assert
            Assert.AreEqual(2, result.Count);
            Assert.AreEqual("Alice", result[0]);
            Assert.AreEqual("Bob", result[1]);
            Assert.AreEqual(3, result.TotalPages);
            Assert.IsTrue(result.HasNextPage);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from previous tests (static queue)
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _service?.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesCorrectCreateMessage()
        {
            // Act
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesCorrectUpdateMessage()
        {
            // Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "teacher");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
            Assert.AreEqual("UPDATE", notification.Operation);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesCorrectDeleteMessage()
        {
            // Act
            _service.SendNotification("Department", "5", "Math", EntityOperation.DELETE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Department 'Math' has been deleted", notification.Message);
            Assert.AreEqual("DELETE", notification.Operation);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _service.SendNotification("Student", "42", null, EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
        {
            // Act
            _service.SendNotification("Student", "42", "  ", EntityOperation.UPDATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student (ID: 42) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Act
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_TwoParamOverload_SendsCorrectly()
        {
            // Act (use the 4-parameter overload that doesn't include display name)
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("New Student (ID: 1) has been created", notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleNotifications_ReturnsFIFO()
        {
            // Arrange
            _service.SendNotification("A", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
            _service.SendNotification("C", "3", "Third", EntityOperation.DELETE);

            // Act & Assert
            var first = _service.ReceiveNotification();
            Assert.AreEqual("A", first.EntityType);

            var second = _service.ReceiveNotification();
            Assert.AreEqual("B", second.EntityType);

            var third = _service.ReceiveNotification();
            Assert.AreEqual("C", third.EntityType);

            var none = _service.ReceiveNotification();
            Assert.IsNull(none);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act (no-op implementation, should not throw)
            _service.MarkAsRead(1);
            _service.MarkAsRead(999);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act
            _service.Dispose();
            // No exception means success
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAt()
        {
            // Act
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreNotEqual(default, notification.CreatedAt);
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Act
            _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsFalse(notification.IsRead);
        }
    }
}

