    [TestClass]
    public sealed class NotificationsControllerTests
    {
        [TestInitialize]
        public void Setup()
        {
            // Drain the static queue before each test
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
            // Verify the value contains the expected properties
            var value = result.Value;
            Assert.IsNotNull(value);
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var service = new NotificationService();
            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
            service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
        }

        [TestMethod]
        public void GetNotifications_LimitsToTenResults()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Student", i.ToString(), $"Student {i}", EntityOperation.CREATE);
            }

            var controller = new NotificationsController(context);

            // Act
            var result = controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            // The controller limits to 10 notifications per request
            // Remaining 5 are still in the queue
        }

        [TestMethod]
        public void MarkAsRead_ValidId_ReturnsSuccess()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.MarkAsRead(1);

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
        }

        [TestMethod]
        public void MarkAsRead_InvalidId_ReturnsSuccess()
        {
            // Arrange - MarkAsRead is a no-op, so any ID should succeed
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.MarkAsRead(999);

            // Assert
            Assert.IsNotNull(result);
            Assert.IsInstanceOfType<JsonResult>(result);
        }

        [TestMethod]
        public void Index_ReturnsView()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new NotificationsController(context);

            // Act
            var result = controller.Index();

            // Assert
            Assert.IsInstanceOfType<ViewResult>(result);
        }
    }
}

