namespace ContosoUniversity.Tests
{
    // Concrete subclass for testing abstract BaseController
    internal class TestableBaseController : BaseController
    {
        public TestableBaseController(SchoolContext context) : base(context)
        {
        }

        public void TestSendNotification(string entityType, string entityId, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, operation);
        }

        public void TestSendNotificationWithDisplayName(string entityType, string entityId, string displayName, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, displayName, operation);
        }

        public void TestDispose()
        {
            Dispose(true);
        }
    }

    [TestClass]
    public sealed class BaseControllerTests
    {
        [TestMethod]
        public void Constructor_SetsDbContext()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();

            // Act
