        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new TestableBaseController(context);

            // Act & Assert - should not throw
            controller.TestSendNotification("Student", "1", EntityOperation.CREATE);
        }

        [TestMethod]
        public void SendEntityNotification_WithDisplayName_DoesNotThrow()
        {
            // Arrange
            using var context = TestHelper.CreateInMemoryContext();
            var controller = new TestableBaseController(context);

            // Act & Assert - should not throw
            controller.TestSendNotificationWithDisplayName("Student", "1", "John Doe", EntityOperation.CREATE);
        }

