        }

        [TestMethod]
        public void Dispose_DisposesNotificationService()
        {
            // Arrange
            var context = TestHelper.CreateInMemoryContext();
            var controller = new TestableBaseController(context);

            // Act & Assert - should not throw during dispose
            controller.TestDispose();
        }
    }
